import React, { useState, useEffect } from "react";
import {Link,Routes, Route, Navigate,useParams} from 'react-router-dom';
import axios from "axios";
import './Design.css';
function Cart(){
    const[Name,setUserName]=useState('');
    const[Dated,setOrderDate]=useState('');
    const[Address,setAddress]=useState('');
    const[Phone,setPhone]=useState('');
    const[Email,setEmail]=useState('');
    
    const[carts,setCart]=useState([]);

    const handleClick=(e)=>{
        e.preventDefault()
        const cart={Name,Dated,Address,Phone,Email}
        console.log(cart)
        fetch("http://localhost:8080/user/addCart",
        {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify(cart)
        }).then(()=>{alert("Added to Cart")})
        }

        const queryParams = new URLSearchParams(window.location.search);
        const id = queryParams.get('id');
        console.log(id);

       const giftGet = (id)=>{
            fetch(`http://localhost:8080/user/selectGift?id=${id}`)
            .then(res=>res.json())
            .then((result)=>{
              setCart(result);
              console.log(setCart);
              return setCart;
            }
          )
          }

const CartValue = giftGet(id)

return ( <>

<div className="topnav">
<a className="pad" id="">Curtain Gifts</a> 
        <a id="productHomeButton"> <Link to = "/home" className="link"> Home  </Link> </a>
        <a id="productOrderButton"> < Link to = "/user/orders" className="link"> Orders </Link> </a>
<a className="padr"> < Link to = "/login" className="link">Logout</Link></a>
</div> 
<div>
    <div>
    <div className="titlebar"> 
            Add Themes
            </div>

<div>

<div  className="form">
            <br></br><br/>
            <form >
            <input placeholder = "Enter Your Name" type = "text" id = "enterUserName" name="enterUserName" value={Name} onChange={(e)=>setUserName(e.target.value)}></input>
            <br></br>
            <input placeholder = "Enter Order Date" type = "Date" id =  "enterOrderDate" name = "enterOrderDate" value={Dated} onChange={(e)=>setOrderDate(e.target.value)}></input>
            <br></br>
            <input placeholder = "Enter Your Address" type = "text" id =  "enterUserAddress" name = "enterUserAddress" value={Address} onChange={(e)=>setAddress(e.target.value)}></input>
            <br></br>
            <input placeholder = "Enter Your Phone Number" type = "number" id =  "enterUserPhone" name =  "enterUserPhone" value={Phone} onChange={(e)=>setPhone(e.target.value)}></input>
            <br></br>
            <input placeholder = "Enter Your Address" type = "text" id =  "enterUserEmail" name = "enterUserEmail" value={Email} onChange={(e)=>setEmail(e.target.value)}></input>
            <br></br>
            </form>
            <br/>
            <h1>{id}</h1>
            <div className="center">
            <button  id = "submitButton" type='submit' value="Submit" onClick={handleClick}> Place Order </button>
            <br></br>
            </div>
            <br></br>
            </div>

</div>

                <div> 
                    < div id = {CartValue.id}>                
                    {CartValue.giftName} 
                    <t/>
                    {CartValue.giftPrice}
                    <t/>
                    {CartValue.giftDesc}
                    <t/>
                    </div>
                <br/>
                </div>
            
</div>
</div>
    </>)
}

export default Cart;
